[][1417] +    // as defined by the advanceHeight/width.
[][1418] +    // See also: https://docs.microsoft.com/en-us/windows/win32/api/dwrite/ns-dwrite-dwrite_glyph_metrics
[][1419] +
[][1420] +    // The scale is a multiplier and the translation is addition. So *1 and +0 will mean nothing happens.
[][1421] +    const float defaultBoxVerticalScaleFactor = 1.0f;
[][1422] +    float boxVerticalScaleFactor = defaultBoxVerticalScaleFactor;
[][1423] +    const float defaultBoxVerticalTranslation = 0.0f;
[][1424] +    float boxVerticalTranslation = defaultBoxVerticalTranslation;
[][1425] +    {
