[][1427] +
[][1428] +        // Ascent is how far up from the baseline we'll draw.
[][1429] +        // verticalOriginY is the measure from the topLeft corner of the bounding box down to where
[][1430] +        // the glyph's version of the baseline is.
[][1431] +        // topSideBearing is how much "gap space" is left between that topLeft and where the glyph
[][1432] +        // starts drawing. Subtract the gap space to find how far is drawn upward from baseline.
[][1433] +        const auto boxAscentDesignUnits = boxMetrics.verticalOriginY - boxMetrics.topSideBearing;
[][1434] +
[][1435] +        // Descent is how far down from the baseline we'll draw.
[][1436] +        // advanceHeight is the total height of the drawn bounding box.
[][1437] +        // verticalOriginY is how much was given to the ascent, so subtract that out.
[][1438] +        // What remains is then the descent value. Remove the
[][1439] +        // bottomSideBearing as the "gap space" on the bottom to find how far is drawn downward from baseline.
[][1440] +        const auto boxDescentDesignUnits = boxMetrics.advanceHeight - boxMetrics.verticalOriginY - boxMetrics.bottomSideBearing;
