[][1443] +        const auto boxHeightDesignUnits = boxAscentDesignUnits + boxDescentDesignUnits;
[][1444] +
[][1445] +        // Second, find the dimensions of the cell we're going to attempt to fit within.
[][1446] +        // We know about the exact ascent/descent units in pixels as calculated when we chose a font and
[][1447] +        // adjusted the ascent/descent for a nice perfect baseline and integer total height.
[][1448] +        // All we need to do is adapt it into Design Units so it meshes nicely with the Design Units above.
[][1449] +        // Use the formula: Pixels * Design Units Per Em / Font Size = Design Units
[][1450] +        const auto cellAscentDesignUnits = ascentPixels * fontMetrics.designUnitsPerEm / scaledFontSize;
[][1451] +        const auto cellDescentDesignUnits = descentPixels * fontMetrics.designUnitsPerEm / scaledFontSize;
[][1452] +        const auto cellHeightDesignUnits = cellAscentDesignUnits + cellDescentDesignUnits;
[][1453] +
[][1454] +        // OK, now do a few checks. If the drawn box touches the top and bottom of the cell
[][1455] +        // and the box is overall tall enough, then we'll not bother adjusting.
[][1456] +        // We will presume the font author has set things as they wish them to be.
[][1457] +        const auto boxTouchesCellTop = boxAscentDesignUnits >= cellAscentDesignUnits;
[][1458] +        const auto boxTouchesCellBottom = boxDescentDesignUnits >= cellDescentDesignUnits;
[][1459] +        const auto boxIsTallEnoughForCell = boxHeightDesignUnits >= cellHeightDesignUnits;
